const onFeatureClick = (feature,layerId) => {
// debugger
console.log(feature, layerId, 'test01');
console.log(global.dashboardGlobalVariables.selectedIndicatorIndex, global.dashboardGlobalVariables.activeTopic, '02');
/* 若是小流域的自动站，则不做跳转到一张图的操作 */
// if (feature?.properties?.CODE_WQDATASOURCETYPE === 'smallWater') {
//   return;
// }
const baseUrl = '/lego-generated-apps/lego_file/app/src/18547eef59454bff840ff42ee0d03b78_6/index.html?{query}#/root'
// 跳转携带的参数
let params = {};
const layerMap = {
  '行政区-air': {
    pageCode: 'air',
    menuId: '14867d5c-dad5-4b04-821f-21f11644eee7'
  },
  '行政区-water-1&2': {
    showDialog: true,
    showDialogSize: 'small',
    pageCode: 'water',
    menuId: 'cef0bf1d-0f04-4c1d-bb9d-d773a8fd724a',
    hideMap: 'true',
    dialogType: '水环境-评价结果',
    monitorTime: global.dashboardGlobalVariables.waterTime
  },
  '行政区-water-3': {
    pageCode: 'water',
    menuId: 'ae03c23f-b550-4e93-966c-2cd7856d67fd'
  },
  // 信访
  '行政区-complaints': {
    pageCode: 'petition',
    menuId: ''
  },
  '空气站': {
    pageCode: 'air',
    menuId: '14867d5c-dad5-4b04-821f-21f11644eee7'
  },
  '业务图层-water-1': {
    pageCode: 'water',
    menuId: 'fdba2188-dcdb-495a-98f8-ee783e9ead90'
  },
  // 饮用水
  '业务图层-water-2': {
    pageCode: 'water',
    menuId: '42373558-b6b0-466e-b5ee-95a2194a9f54'
  },
  '业务图层-water-3': {
    pageCode: 'water',
    menuId: 'ae03c23f-b550-4e93-966c-2cd7856d67fd'
  },
  '水自动站': {
    pageCode: 'water',
    menuId: 'ad1dddaf-8dff-4bfe-bdda-2e205599137f'
  },
  '问题清单': {
    pageCode: 'petition',
    menuId: '8feb6f86-5c2b-404f-b86a-65fc7d15bddf'
  }
}

const { activeTopic } = global.dashboardGlobalVariables;

if (layerId === '行政区') {
  if (global.dashboardGlobalVariables.activeTopic === 'water' && [1, 2].includes(global.dashboardGlobalVariables.selectedIndicatorIndex)) {
    params = {
      ...layerMap['行政区-water-1&2'],
    };
  } else if (global.dashboardGlobalVariables.activeTopic === 'water' && global.dashboardGlobalVariables.selectedIndicatorIndex === 3) {
    params = {
      ...layerMap['行政区-water-3'],
    };
  } else if (activeTopic === 'supervision') {
    // 督查督办  现在督查督办也会跳转到信访
    params = {
      ...layerMap['行政区-complaints'],
    };

  } else if (activeTopic === 'complaints') {
    // 信访
    params = {
      ...layerMap['行政区-complaints'],
    };

  } else if (global.dashboardGlobalVariables.activeTopic === 'air') {
    global.dialogParams = { ...feature.properties };
    global.dialogName = 'airOverviewPopComponent';
    console.log(global.dialogParams, '大气区域弹窗');
  } else {
    params = {
      ...layerMap['行政区-air'],
    };
  }
  params = {
    ...params,
    pointValue: feature?.properties?.XZQDM,
    regionName: feature?.properties?.XZQMC,
    switchType: 'openDialog'
  };
  // 查询参数
  // const searchParams = new URLSearchParams(params).toString();
  // // 跳转链接
  // const url = searchParams ? `${baseUrl.replace('{query}', searchParams)}` : baseUrl.replace('{query}', '');
  // window.open(url, '_blank');
} else if (layerId === '业务图层') {
  if (global.dashboardGlobalVariables.activeTopic === 'water' || global.dashboardGlobalVariables.activeTopic === 'WuYiShanNationalParkWaterQualityRatio') {
    /* 水环境的专题 */
    if (global.dashboardGlobalVariables.selectedIndicatorIndex === 1 || global.dashboardGlobalVariables.selectedIndicatorIndex === 35) {
      /* 地表水 */
      params = {
        ...layerMap['业务图层-water-1'],
        hideMap: 'true',
        monitorTime: feature?.geometry?.time,
        dialogType: '地表水',
        showDialog: true,
        showDialogSize: 'large',
      };
      console.log(params, 'test001');
    } else if (global.dashboardGlobalVariables.selectedIndicatorIndex === 2) {
      /* 饮用水 */
      params = {
        ...layerMap['业务图层-water-2'],
        region: feature?.properties?.MANAGER_TYPE_CODE,
        monitortime: feature?.properties?.MONITORTIME,
        hideMap: 'true',
        monitorTime: feature?.properties?.MONITORTIME,
        dialogType: '饮用水',
        showDialog: true,
        showDialogSize: 'large',
      };
      console.log(params, '002');
    }
    else if (global.dashboardGlobalVariables.selectedIndicatorIndex === 3) {
      /* CWQI */
      params = {
        ...layerMap['业务图层-water-3'],
      };

    } else if (global.dashboardGlobalVariables.selectedIndicatorIndex === 33) {
      // 巡河交水
      params = {
        ...layerMap['业务图层-water-2'],
        region: feature?.properties?.MANAGER_TYPE_CODE,
        monitortime: feature?.properties?.MONITORTIME,
        hideMap: 'true',
        monitorTime: feature?.properties?.MONITORTIME,
        dialogType: '巡河交水',
        showDialog: true,
        showDialogSize: 'large',
      };
      console.log(params, '003');
    }
    params = {
      ...params,
      pointValue: JSON.stringify({
        pointCode: feature?.properties?.POINT_CODE,
      }),
      switchType: 'openDialog'
    };
    console.log(params, '004');
  } else if (global.dashboardGlobalVariables.activeTopic === 'air') {
    params = {
      ...layerMap['行政区-air'],
      pointValue: feature?.properties?.POINT_CODE,
      switchType: 'regionChange'
    };
  } else if (global.dashboardGlobalVariables.activeTopic === 'complaints' && global.dashboardGlobalVariables.selectedIndicatorIndex === 16) {
    global.dashboardGlobalVariables.dailyComplaint.complaintListItemName = feature.properties.enter_name;
    global.dashboardGlobalVariables.dailyComplaint.startTime = '';
    global.dashboardGlobalVariables.dailyComplaint.endTime = '';
    rootData.rootSocket.emit(
      'message',  // 固定的消息名称，不能修改
      {
        room: global.socketRoom,  // 房间号，一般使用全局变量socketRoom
        type: 'createDialog',  // 消息类型名称
        data: {
          data: {
            headerComName: "",
            contentComName: "repeatObjDetailsPopComponent",
            maxWidth: "1600px",
            maxHeight: "930px",
            minWidth: "1000px",
            minHeight: "500px",
            isScalse: false,
            title: "重复投诉对象详情"
          }
        }
      }
    );
  }
} else if (layerId === '空气站') {
  /* 空气站 */
  params = {
    ...layerMap['空气站'],
    pointValue: JSON.stringify({
      pointCode: feature?.properties?.POINT_CODE,
      pointType: feature?.properties?.POINT_TYPE,
    }),
    switchType: 'openDialog',
    hideMap: 'true',
    monitorTime: feature?.geometry?.time,
    pointInfo: JSON.stringify({ ...feature?.properties, ...{ pointType: feature?.properties?.POINT_TYPE } }),
    roomId: global.socketRoom,
    dialogType: '空气站',
    showDialog: true,
    showDialogSize: 'large',
  };
} else if (layerId === '水自动站') {
  params = {
    ...layerMap['水自动站'],
    pointValue: JSON.stringify({
      pointCode: feature?.properties?.POINT_CODE,
    }),
    switchType: 'openDialog',
    hideMap: 'true',
    pointInfo: JSON.stringify({ ...feature?.properties, ...{ MONITORTIME: feature?.geometr?.time, dialogType: 'autoHour' } }),
    monitorTime: feature?.geometry?.time,
    roomId: global.socketRoom,
    dialogType: '水自动站',
    showDialog: true,
    showDialogSize: 'large',
  };
} else if (layerId === '问题清单') {
  params = {
    ...layerMap['问题清单'],
    pointValue: feature?.properties?.PKID,
    switchType: 'openDialog',
    hideMap: 'true',
    monitorTime: feature?.geometry?.time,
    pointInfo: JSON.stringify({ ...feature?.properties, ...{ MONITORTIME: feature?.geometr?.time } }),
    roomId: global.socketRoom,
    // dialogType: '问题清单',
  };
}
// 查询参数
const searchParams = decodeURIComponent(new URLSearchParams(params).toString());
// 跳转链接
const url = searchParams ? `${baseUrl.replace(/{query}/g, searchParams)}` : baseUrl.replace('{query}', '');

// console.log(searchParams, baseUrl, url, 'test004');
if (params?.showDialog && params?.showDialogSize) {
  if (params?.showDialogSize === 'large') {
    state.dialogUrlSmall = '';
    state.dialogUrlLarge = url;
  }
  if (params?.showDialogSize === 'small') {
    state.dialogUrlSmall = url;
    state.dialogUrlLarge = '';
  }
}

if (!params?.showDialog) {
  state.dialogUrlSmall = '';
  state.dialogUrlLarge = '';
}

// window.open(url, '_blank');
console.log(url, '03');


};
